# Compute the lattices in Minkowski space
def prepare_matrices():
    global cm, key, cmi, cmqq
    print("Preparing matrices.")
    cm, key = cmatrix()
    cmi = cm.inverse()
    cm53 = cm.change_ring(RealField(_sage_const_10 ))
