def go_to_q(a_vec, matchange):
    pol = make_poly(a_vec, matchange, x)
    pol_eval = pol.subs(x=_sage_const_1 )
    return Zq(pol_eval)

def sanity_check():
    print("Initiating sanity check...")
    mat = cmi
    pvec1 = random_vec(q, n)
    vec1 = cm * pvec1
    pvec2 = random_vec(q, n)
    vec2 = cm * pvec2
    vprod2 = vecmul_poly(vec1, vec2, cm, cmi)
    first_thing = go_to_q(vprod2, mat)
    second_thing = go_to_q(vec1, mat) * go_to_q(vec2, mat)
    if first_thing == second_thing:
        print("Sanity confirmed.")
    else:
        print("!!! SANITY ERROR !!!")
    return True

def histoq(data):
    hist = [_sage_const_0  for i in range(_sage_const_10 )]
    zeroct = _sage_const_0 
    for datum in data:
        if datum == _sage_const_0 : zeroct += _sage_const_1 
        histbit = floor(ZZ(datum)*_sage_const_10 /q)
        if histbit > _sage_const_9 : histbit = _sage_const_9 
        hist[histbit] += _sage_const_1 
    return [hist, zeroct]

def histo(data, cmi_mat):
    return histoq([go_to_q(datum, cmi_mat) for datum in data])

