def alg2(reportrate, quickflag=False):
    print("Beginning algorithm 2.")
    numsamps = len(samps)
    a_vals = [go_to_q(s[_sage_const_0 ], cmi) for s in samps]
    b_vals = [go_to_q(s[_sage_const_1 ], cmi) for s in samps]
    
    winner = [[], _sage_const_0 ]
    
    for round_idx in range(_sage_const_2 ):
        if round_idx == _sage_const_0 :
            print("ROUND 1: Peeking at real secret.")
            iterat = [lift_s]
        else:
            print("ROUND 2: Running attack naively.")
            iterat = range(_sage_const_1000 ) if quickflag else range(q)
            
        possibles = []
        for g in iterat:
            if Mod(g, reportrate) == _sage_const_0 : print(f"Checking residue {g}")
            g_zq = Zq(g)
            potential = True
            ctr = _sage_const_0 
            while ctr < numsamps and potential:
                e = abs(lift(Zq(b_vals[ctr] - g_zq * a_vals[ctr])))
                if q/_sage_const_4  < e < _sage_const_3 *q/_sage_const_4 :
                    potential = False
                else:
                    ctr += _sage_const_1 
            
            if ctr >= winner[_sage_const_1 ]:
                if ctr > winner[_sage_const_1 ]: winner = [[g_zq], ctr]
                else: winner[_sage_const_0 ].append(g_zq)
            
            if potential: possibles.append(g_zq)

    print(f"Real secret mod q was: {lift_s}")
    if lift_s in possibles:
        print("Success! Secret found.")
        return True
    return False

def shebang(fval, qval, sval, numsampsval, numtrials, quickflag=False):
    global sig
    print("Welcome to the Ring-LWE Attack.")
    n_deg = fval.degree()
    
    setup_params(fval, qval, sval)
    prepare_matrices()
    
    initiate_sampler()
    count_successes = _sage_const_0 
    
    for trialnum in range(numtrials):
        print(f"\n--- TRIAL {trialnum} ---")
        create_secret()
        create_samples(numsampsval)
        sanity_check()
        secret_mod_q()
        if alg2(_sage_const_10000 , quickflag):
            count_successes += _sage_const_1 
            
    print(f"\nFinal Result: {count_successes}/{numtrials} successes.")
    return count_successes


